INSERT INTO `dishes` VALUES (1,'Classic Burger','Bun + Patty + Cheddar + Veggies',9.90,'2025-08-12 00:31:44','2025-08-12 00:31:44','01K2DV1BF7P8BQTMKM723RP601'),(2,'Dish 1','Quod commodi ullam placeat facilis.',14.63,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1EX24FXSW0ZPAB2AY8BE'),(3,'Dish 2','Officiis et expedita quis.',6.32,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1EXPBRB3H9AK6WGNNC5J'),(4,'Dish 3','Delectus dolor repellat iusto voluptatibus qui.',24.71,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1EY687SP4X7WED8DVJCV'),(5,'Dish 4','Eum praesentium quasi impedit natus aut ut voluptas.',9.43,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1EZ0XKSPCDER649GC1FG'),(6,'Dish 5','Tenetur corporis aliquid exercitationem recusandae assumenda quibusdam.',5.88,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F2S861J6B2ZEFBGBDBM'),(7,'Dish 6','Sed vitae magni dolorem voluptates veniam autem veritatis.',12.59,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F3F7QDZC9R1HNEMBGW0'),(8,'Dish 7','Sit voluptatem autem sit consequatur sit voluptate consequuntur.',13.76,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F3ZW7E1HVF2548CFXQZ'),(9,'Dish 8','Dolores aut ipsum praesentium sit enim libero sapiente.',24.95,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F4EFJ3HS7KH82QYYZ4C'),(10,'Dish 9','Dolorem molestiae nulla et consequatur sapiente.',8.75,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F50KMG6BW8SY9AHXH9B'),(11,'Dish 10','Molestias odio accusantium deleniti consequatur minus.',5.15,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F5V7JXZ13WSXFMVPZHA'),(12,'Dish 11','Ut porro aliquam quae architecto corporis quo veniam.',21.72,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F6APH72T9NFZEFZFG3Q'),(13,'Dish 12','Et magnam earum voluptatem enim.',5.81,'2025-08-12 00:31:47','2025-08-12 00:31:47','01K2DV1F74X5K58F5K616JXF09'),(14,'Dish 13','Provident est qui quibusdam qui.',23.04,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FAYNP13JEF8785R2Q0G'),(15,'Dish 14','Eius quam voluptatem hic omnis.',16.45,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FBE0V5BK763TMW1E56Y'),(16,'Dish 15','Atque aperiam quisquam velit qui excepturi.',8.08,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FC0JER3JCS8YGXFRQ2C'),(17,'Dish 16','Ullam vitae qui consequatur nemo voluptatem.',22.64,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FCG7AN9R658Y22N62H9'),(18,'Dish 17','Cum quis dolorum repellat recusandae ea magnam.',20.40,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FCYARF7D40TNFP1P3XA'),(19,'Dish 18','Eveniet deleniti maxime cumque quibusdam maiores aut cumque.',6.55,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FDT32037V3JWTR8AHB5'),(20,'Dish 19','Et laborum ad laborum accusantium.',19.09,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FEM9J74JSNR976E496D'),(21,'Dish 20','Architecto et ea voluptas ad hic saepe asperiores.',14.33,'2025-08-12 00:31:48','2025-08-12 00:31:48','01K2DV1FF2Z93VDV7HHGYV5S8M');
